def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 60 + np.log1p(cap) * 30 + np.exp(-usage)
        fluctuation = 0.0
        complexity = 1.0
        if usage > 5:
            base_priority += 8000 * np.power(usage, 1.25)
            complexity *= 1.4
            if cap > 15:
                base_priority += (np.cbrt(cap) ** 2) * 120 + 50 * np.cos(cap * 2)
            else:
                base_priority -= 60 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 30 / i**1.1
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2400 * delta ** 2 + 300 * (1 - delta ** 0.4)
            for j in range(2, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 30 / (j ** 0.9)
            if int(cap * 4) % 5 == 2:
                base_priority += 60 * np.tan(cap / 20)
            complexity *= 1.3
        elif 3 < usage <= 4:
            base_priority += 1700 * (usage - 3)**2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 20 / k
                    if k % 6 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 25 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.1 < 0.7:
                base_priority += 45 * np.sin(cap * 4)
            complexity *= 1.2
        elif 2 < usage <= 3:
            base_priority += 1500 * (usage - 2)**3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.75:
                    fluctuation += pwr * 35 / m
                    if m % 4 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 20 / (m + 4)
                    if m == 14 and usage > 2.7:
                        fluctuation += 28
            if cap % 2.7 < 0.6:
                base_priority += 40 * np.cos(cap * 3.5)
            complexity *= 1.15
        elif 1 < usage <= 2:
            base_priority += 1100 * (usage - 1) ** 3.5
            for n in range(1, 21):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 30 / n
                    if n % 5 == 3:
                        fluctuation -= n * 4
                else:
                    fluctuation += (1 - pwr) * 15 / (n + 2)
                    if n == 18 and usage > 1.8:
                        fluctuation += 22
            if cap % 1.8 < 0.45:
                base_priority += 35 * np.sin(cap * 2.5)
            complexity *= 1.1
        elif 0.4 < usage <= 1:
            base_priority += 160 * (1 - usage)
            for o in range(1, 16):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.08 * o:
                    fluctuation -= 10 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 45
            else:
                base_priority += (cap % 7) * 30
            complexity *= 1.05
        else:
            base_priority += 320 * (1 - usage) ** 2.5
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 20 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1:
                base_priority += np.log1p(cap * 30) * 55
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation * complexity
        if cap < 0.03:
            priority += 90
            if usage > 0.8:
                priority += 110
            elif usage < 0.1:
                priority -= 70
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 50
            if usage > 0.9:
                priority += 80
            elif usage < 0.25:
                priority -= 40
            for r in range(1, 8):
                if int(cap * 1500) % (r + 6) == 1:
                    priority += r * 9
                else:
                    priority -= r * 5
        else:
            if usage < 0.15:
                priority -= 60
                for s in range(1, 9):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 120
                for t in range(1, 7):
                    priority += t * 12
            else:
                priority += 50
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 20
        if int(cap * 1200) % 29 == 0:
            proximity -= 15
        if int(cap * 250) % 11 == 0:
            proximity += 18
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.015:
                proximity += 25 / u
            elif diff < 0.045:
                proximity += 14 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_chk = int(cap * 2000) % (v + 11)
            if mod_chk == 1:
                proximity += v * 6
            elif mod_chk == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1800) % (w + 8)
            if mod_chk == 1:
                proximity += 15 * w
            elif mod_chk == 4:
                proximity -= 10 * w
        priority += proximity
        if usage < 0.002:
            for x in range(1, 10):
                priority -= x * 15
        elif usage > 0.98:
            for y in range(1, 8):
                priority += y * 15
        if cap > 3.0:
            if cap % 1.2 < 0.08:
                priority += 50
            if (int(cap * 3000) % 29 == 0) and (usage > 0.8):
                priority += 80
            for z in range(1, 8):
                if (int(cap * 700) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
